import React, { useEffect, useContext } from 'react';
import { BrowserRouter as Router, Routes, Route, Navigate } from 'react-router-dom';
import { AuthProvider, AuthContext } from './context/AuthContext';
import Login from './pages/Login';
import Register from './pages/Register';
import WorkerDashboard from './pages/WorkerDashboard';
import EmployerDashboard from './pages/EmployerDashboard';
import JobDetails from './pages/JobDetails';
import PrivateRoute from './components/PrivateRoute';
import Navbar from './components/Navbar';
import Home from './pages/Home';
import PostJob from './pages/PostJob';
import BrowseWorkers from './pages/BrowseWorkers';
import socket from './utils/socket';

const AppContent = () => {
  const { user } = useContext(AuthContext);

  useEffect(() => {
    if (user) {
      socket.connect();
      socket.emit('join', user.id);

      socket.on('job-match', (data) => {
        alert(`New Job Match: ${data.jobTitle} (${data.matchPercentage}%)`);
      });

      socket.on('job-assigned', (data) => {
        alert(`Good news! You've been hired for: ${data.jobTitle}`);
      });

      socket.on('new-application', (data) => {
        alert(`New application received for: ${data.jobTitle}`);
      });

      return () => {
        socket.off('job-match');
        socket.off('job-assigned');
        socket.off('new-application');
        socket.disconnect();
      };
    }
  }, [user]);

  return (
    <Router>
      <div className="App">
        <Navbar />
        <Routes>
          <Route path="/" element={<Home />} />
          <Route path="/login" element={<Login />} />
          <Route path="/register" element={<Register />} />
          <Route
            path="/worker/dashboard"
            element={
              <PrivateRoute role="worker">
                <WorkerDashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/employer/dashboard"
            element={
              <PrivateRoute role="employer">
                <EmployerDashboard />
              </PrivateRoute>
            }
          />
          <Route
            path="/post-job"
            element={
              <PrivateRoute role="employer">
                <PostJob />
              </PrivateRoute>
            }
          />
          <Route
            path="/browse-workers"
            element={
              <PrivateRoute role="employer">
                <BrowseWorkers />
              </PrivateRoute>
            }
          />
          <Route
            path="/job/:id"
            element={
              <PrivateRoute>
                <JobDetails />
              </PrivateRoute>
            }
          />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </div>
    </Router>
  );
};

function App() {
  return (
    <AuthProvider>
      <AppContent />
    </AuthProvider>
  );
}

export default App;
